    22→	// Outputs tracks planned changes output values.
    23→	//
    24→	// Note that although an in-memory plan contains planned changes for
    25→	// outputs throughout the configuration, a plan serialized
    26→	// to disk retains only the root outputs because they are
    27→	// externally-visible, while other outputs are implementation details and
    28→	// can be easily re-calculated during the apply phase. Therefore only root
    29→	// module outputs will survive a round-trip through a plan file.
    30→	Outputs []*OutputChangeSrc
    31→}
